void findK_openmp(	long item_9,
					knode *x_8,
					long elem_2,
					record *x_1,
					long *data_0,
					long *item_7,
					int *data_4, 
					record *item_6,
					int numBlocks,
					int threadsPerBlock)
{
	int i;
	int tmp_5;
	int item_3;

	#pragma omp parallel for private(i, tmp_5, item_3)
	for(tmp_5 = 0; tmp_5 < numBlocks; tmp_5++) {
		for(i = 0; i < item_9; i++) {
			#pragma omp parallel private(item_3)
			{
				item_3 = omp_get_thread_num();
				if(item_3 < threadsPerBlock) {
					if(data_4[tmp_5] >= (x_8[data_0[tmp_5]].keys[item_3]) && (data_4[tmp_5] < x_8[data_0[tmp_5]].keys[item_3+1])) {
						if(elem_2 > x_8[item_7[tmp_5]].indices[item_3]) {
							item_7[tmp_5] = x_8[item_7[tmp_5]].indices[item_3];
						}
					}
				}
				#pragma omp barrier

				if(item_3 == 0) {
					data_0[tmp_5] = item_7[tmp_5];
				}
				#pragma omp barrier
			}
		}

		item_3 = 0;
		if(data_4[tmp_5] == x_8[data_0[tmp_5]].keys[item_3]) {
			item_6[tmp_5].value = x_1[x_8[data_0[tmp_5]].indices[item_3]].value;
		}
	}
}

void kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,
						int order,
						long maxheight,
						int count,
						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	time1 = get_time();

	int numBlocks = count;
	int threadsPerBlock = 1024 > order ? order : 1024;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", numBlocks, threadsPerBlock);

	time2 = get_time();

	time3 = get_time();

	findK_openmp(maxheight, knodes, knodes_elem, records, currKnode, offset, keys, ans, numBlocks, threadsPerBlock);

	time4 = get_time();

	time5 = get_time();

	time6 = get_time();

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("%15.12f s, %15.12f %% : GPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f %% : GPU MEM: ALO\n", 					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f %% : GPU MEM: COPY IN\n",					(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f %% : GPU: KERNEL\n",						(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f %% : GPU MEM: COPY OUT\n",				(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f %% : GPU MEM: FRE\n", 					(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);
	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time6-time0) / 1000000);
}

